import React, { useState } from 'react';
import type { MenuProps } from 'antd';
import { Button, Dropdown, Space } from 'antd';
import { useTranslation } from 'react-i18next';
import { BsFillMoonStarsFill, BsFillSunFill } from 'react-icons/bs';
import { changeTheme } from '../../Hooks/useChangeTheme';

const Lung: React.FC = () => {
  let What_the_Theme = localStorage.getItem('theme') ?? 'light';
  if (What_the_Theme === 'dark') {
    document.body.classList.add('dark');
  }
  const [theme, setTheme] = useState('light');
  const { t } = useTranslation();

  const LightTheme = () => {
    return (
      <div onClick={() => changeTheme('light', What_the_Theme)}>
        <BsFillSunFill />
        {t('light')}
      </div>
    );
  };

  const DarkTheme = () => {
    return (
      <div onClick={() => changeTheme('dark', What_the_Theme)}>
        <BsFillMoonStarsFill />
        {t('dark')}
      </div>
    );
  };

  const items: MenuProps['items'] = [
    {
      key: '1',
      label: <LightTheme />,
    },
    {
      key: '2',
      label: <DarkTheme />,
    },
  ];

  return (
    <Space direction="vertical">
      <Dropdown menu={{ items }} placement="top">
        <Button>
          {What_the_Theme === 'dark' ? <DarkTheme /> : <LightTheme />}
        </Button>
      </Dropdown>
    </Space>
  );
};

export default Lung;
